import{_ as a,o as l,c as o,ae as i}from"./chunks/framework.S2bkbjdq.js";const h=JSON.parse('{"title":"NRP Routing Spec","description":"","frontmatter":{},"headers":[],"relativePath":"nrp-routing-spec.md","filePath":"nrp-routing-spec.md"}'),r={name:"nrp-routing-spec.md"};function c(t,e,n,s,d,p){return l(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="nrp-routing-spec" tabindex="-1">NRP Routing Spec <a class="header-anchor" href="#nrp-routing-spec" aria-label="Permalink to &quot;NRP Routing Spec&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>This document fixes the boundary between <code>.me</code>, <code>nrp</code>, and the <code>cleaker</code> server.</p><ul><li><code>.me</code> is the local semantic kernel.</li><li><code>nrp</code> is the semantic addressing layer.</li><li><code>cleaker</code> server is an HTTP transport and persistence surface for remote namespaces.</li></ul><p>The server must expose <code>cleaker.me</code> and related HTTP routes. It must not redefine <code>nrp://local</code> as a network resource.</p><h2 id="layer-contract" tabindex="-1">Layer Contract <a class="header-anchor" href="#layer-contract" aria-label="Permalink to &quot;Layer Contract&quot;">​</a></h2><h3 id="me" tabindex="-1"><code>.me</code> <a class="header-anchor" href="#me" aria-label="Permalink to &quot;`.me`&quot;">​</a></h3><p><code>.me</code> owns:</p><ul><li>local state</li><li>local execution</li><li>local memory replay</li><li>local path semantics</li></ul><p>Examples:</p><ul><li><code>profile.name</code></li><li><code>friends.ana.bio</code></li><li><code>friends[age &gt; 18].name</code></li></ul><h3 id="nrp" tabindex="-1"><code>nrp</code> <a class="header-anchor" href="#nrp" aria-label="Permalink to &quot;`nrp`&quot;">​</a></h3><p><code>nrp</code> owns:</p><ul><li>semantic target identity</li><li>local vs remote addressing</li><li>transport-agnostic destination syntax</li></ul><p>Examples:</p><ul><li><code>nrp://local/profile.name</code></li><li><code>nrp://self/profile.name</code></li><li><code>nrp://ana.cleaker/read/profile</code></li></ul><h3 id="cleaker-server" tabindex="-1"><code>cleaker</code> server <a class="header-anchor" href="#cleaker-server" aria-label="Permalink to &quot;`cleaker` server&quot;">​</a></h3><p>The server owns:</p><ul><li>claim and open flows</li><li>remote namespace persistence</li><li>block append and replay</li><li>HTTP route exposure for remote surfaces</li><li>mapping HTTP host/path requests into canonical namespace strings</li></ul><p>Examples:</p><ul><li><code>POST /claims</code></li><li><code>POST /claims/open</code></li><li><code>POST /</code></li><li><code>GET /</code></li><li><code>GET /blocks</code></li></ul><h2 id="non-goals" tabindex="-1">Non-Goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-Goals&quot;">​</a></h2><p>The server does not own:</p><ul><li>in-process <code>.me</code> execution</li><li><code>nrp://local</code></li><li><code>nrp://self</code></li></ul><p>Those targets are resolved inside the local runtime or binder.</p><h2 id="canonical-target-classes" tabindex="-1">Canonical Target Classes <a class="header-anchor" href="#canonical-target-classes" aria-label="Permalink to &quot;Canonical Target Classes&quot;">​</a></h2><h3 id="local-sovereign-target" tabindex="-1">Local sovereign target <a class="header-anchor" href="#local-sovereign-target" aria-label="Permalink to &quot;Local sovereign target&quot;">​</a></h3><p>Resolved without network.</p><p>Examples:</p><ul><li><code>nrp://local/profile.name</code></li><li><code>nrp://self/profile.name</code></li></ul><p>Expected resolver:</p><ul><li><code>.me</code> kernel</li><li><code>cleaker(me)</code> binder when bound to an in-process kernel</li></ul><h3 id="remote-namespace-target" tabindex="-1">Remote namespace target <a class="header-anchor" href="#remote-namespace-target" aria-label="Permalink to &quot;Remote namespace target&quot;">​</a></h3><p>Resolved through a transport.</p><p>Examples:</p><ul><li><code>nrp://ana.cleaker/read/profile</code></li><li><code>ana.cleaker:read/profile</code></li><li><code>https://cleaker.me/@ana/profile</code></li><li><code>https://ana.cleaker.me/profile</code></li></ul><p>Expected resolver:</p><ul><li><code>cleaker</code> HTTP server</li></ul><h2 id="canonical-namespace-model" tabindex="-1">Canonical Namespace Model <a class="header-anchor" href="#canonical-namespace-model" aria-label="Permalink to &quot;Canonical Namespace Model&quot;">​</a></h2><p>The server should continue using canonical namespace strings as the internal storage key.</p><p>Current examples already implemented:</p><ul><li><code>cleaker.me</code></li><li><code>cleaker.me/users/ana</code></li><li><code>cleaker.me/relations/ana+bella</code></li><li><code>localhost</code></li><li><code>localhost/users/ana</code></li></ul><p>Rule:</p><ul><li>host and path are transport syntax</li><li>canonical namespace is the storage identity</li><li>NRP target is the semantic identity</li></ul><p>These three must map deterministically.</p><h2 id="http-to-namespace-to-nrp-mapping" tabindex="-1">HTTP to Namespace to NRP Mapping <a class="header-anchor" href="#http-to-namespace-to-nrp-mapping" aria-label="Permalink to &quot;HTTP to Namespace to NRP Mapping&quot;">​</a></h2><h3 id="root-host" tabindex="-1">Root host <a class="header-anchor" href="#root-host" aria-label="Permalink to &quot;Root host&quot;">​</a></h3><p>HTTP:</p><ul><li><code>GET https://cleaker.me/</code></li></ul><p>Canonical namespace:</p><ul><li><code>cleaker.me</code></li></ul><p>Canonical NRP:</p><ul><li><code>nrp://cleaker.me/read</code></li></ul><h3 id="user-subdomain" tabindex="-1">User subdomain <a class="header-anchor" href="#user-subdomain" aria-label="Permalink to &quot;User subdomain&quot;">​</a></h3><p>HTTP:</p><ul><li><code>GET https://ana.cleaker.me/</code></li></ul><p>Canonical namespace:</p><ul><li><code>cleaker.me/users/ana</code></li></ul><p>Canonical NRP:</p><ul><li><code>nrp://cleaker.me/users/ana/read</code></li></ul><h3 id="user-path-selector" tabindex="-1">User path selector <a class="header-anchor" href="#user-path-selector" aria-label="Permalink to &quot;User path selector&quot;">​</a></h3><p>HTTP:</p><ul><li><code>GET https://cleaker.me/@ana</code></li></ul><p>Canonical namespace:</p><ul><li><code>cleaker.me/users/ana</code></li></ul><p>Canonical NRP:</p><ul><li><code>nrp://cleaker.me/users/ana/read</code></li></ul><h3 id="symmetric-relation" tabindex="-1">Symmetric relation <a class="header-anchor" href="#symmetric-relation" aria-label="Permalink to &quot;Symmetric relation&quot;">​</a></h3><p>HTTP:</p><ul><li><code>GET https://cleaker.me/@ana+bella</code></li></ul><p>Canonical namespace:</p><ul><li><code>cleaker.me/relations/ana+bella</code></li></ul><p>Canonical NRP:</p><ul><li><code>nrp://cleaker.me/relations/ana+bella/read</code></li></ul><h3 id="nested-directional-path" tabindex="-1">Nested directional path <a class="header-anchor" href="#nested-directional-path" aria-label="Permalink to &quot;Nested directional path&quot;">​</a></h3><p>HTTP:</p><ul><li><code>GET https://cleaker.me/@ana/@bella</code></li></ul><p>Canonical namespace:</p><ul><li><code>cleaker.me/users/ana/users/bella</code></li></ul><p>Canonical NRP:</p><ul><li><code>nrp://cleaker.me/users/ana/users/bella/read</code></li></ul><h3 id="local-dev-host" tabindex="-1">Local dev host <a class="header-anchor" href="#local-dev-host" aria-label="Permalink to &quot;Local dev host&quot;">​</a></h3><p>HTTP:</p><ul><li><code>GET http://localhost:8161/</code></li></ul><p>Canonical namespace:</p><ul><li><code>localhost</code></li></ul><p>Canonical NRP:</p><ul><li><code>nrp://localhost/read</code></li></ul><h3 id="local-dev-user-subdomain" tabindex="-1">Local dev user subdomain <a class="header-anchor" href="#local-dev-user-subdomain" aria-label="Permalink to &quot;Local dev user subdomain&quot;">​</a></h3><p>HTTP:</p><ul><li><code>GET http://ana.localhost:8161/</code></li></ul><p>Canonical namespace:</p><ul><li><code>localhost/users/ana</code></li></ul><p>Canonical NRP:</p><ul><li><code>nrp://localhost/users/ana/read</code></li></ul><h2 id="write-mapping" tabindex="-1">Write Mapping <a class="header-anchor" href="#write-mapping" aria-label="Permalink to &quot;Write Mapping&quot;">​</a></h2><p>For writes, the target resource remains the current resolved namespace.</p><p>Examples:</p><ul><li><code>POST https://cleaker.me/</code> with <code>Host: ana.cleaker.me</code></li><li><code>POST https://cleaker.me/</code> with <code>x-forwarded-host: ana.cleaker.me</code></li></ul><p>Canonical namespace:</p><ul><li><code>cleaker.me/users/ana</code></li></ul><p>Canonical NRP intent:</p><ul><li><code>nrp://cleaker.me/users/ana/write</code></li></ul><p>Claim/open remain namespace operations, not path operations:</p><ul><li><code>POST /claims</code></li><li><code>POST /claims/open</code></li></ul><p>Body:</p><ul><li><code>namespace</code></li><li><code>secret</code></li></ul><h2 id="binder-responsibilities" tabindex="-1">Binder Responsibilities <a class="header-anchor" href="#binder-responsibilities" aria-label="Permalink to &quot;Binder Responsibilities&quot;">​</a></h2><p><code>cleaker(me)</code> should decide resolution by target class:</p><ul><li>local <code>.me</code> expression -&gt; resolve in-process</li><li><code>nrp://local/...</code> -&gt; resolve in-process</li><li><code>nrp://self/...</code> -&gt; resolve in currently bound kernel</li><li><code>ana.cleaker:read/profile</code> or equivalent remote target -&gt; resolve through configured transport</li></ul><p>This means the binder should treat <code>nrp</code> as the router and the server as one transport backend.</p><h2 id="parsing-guidance" tabindex="-1">Parsing Guidance <a class="header-anchor" href="#parsing-guidance" aria-label="Permalink to &quot;Parsing Guidance&quot;">​</a></h2><p>Short-term:</p><ul><li>keep current <code>.cleaker:read/...</code> support</li><li>keep current host/path HTTP routing</li><li>do not force <code>nrp://</code> into the server API yet</li></ul><p>Medium-term:</p><ul><li>add a canonical parser that normalizes: <ul><li><code>ana.cleaker:read/profile</code></li><li><code>nrp://cleaker.me/users/ana/read/profile</code></li><li><code>https://ana.cleaker.me/profile</code></li></ul></li></ul><p>All three should converge to one internal target record.</p><h2 id="server-rules" tabindex="-1">Server Rules <a class="header-anchor" href="#server-rules" aria-label="Permalink to &quot;Server Rules&quot;">​</a></h2><ol><li>The server may expose HTTP routes for remote namespaces.</li><li>The server must never claim ownership of <code>nrp://local</code>.</li><li><code>resolveNamespace(req)</code> should stay transport-facing and return canonical namespace strings.</li><li>A separate normalization layer should map canonical namespace strings to canonical NRP targets.</li><li>Claim/open logic should remain namespace-based, not tied to a particular URL shape.</li></ol><h2 id="immediate-implementation-priority" tabindex="-1">Immediate Implementation Priority <a class="header-anchor" href="#immediate-implementation-priority" aria-label="Permalink to &quot;Immediate Implementation Priority&quot;">​</a></h2><p>The next practical step is not to expose a literal <code>nrp://</code> HTTP endpoint.</p><p>The next step is to add one normalization utility on the server side:</p><ul><li>input: host + path + method</li><li>output: <ul><li>canonical namespace</li><li>canonical NRP target</li><li>operation kind: <code>read</code>, <code>write</code>, <code>claim</code>, <code>open</code></li></ul></li></ul><p>That utility becomes the contract between routing and the engine.</p>',124)])])}const m=a(r,[["render",c]]);export{h as __pageData,m as default};
